// 用唯一 ESM 实例识别构造器新增 style,随后迁入 shadow(铁律 2)
const before = new Set(document.head.querySelectorAll('style'));
const { default: Snowflakes } = await import('https://cdn.jsdelivr.net/npm/magic-snowflakes@7/+esm?ov-shadow=' + crypto.randomUUID());
const el = document.createElement('div'); el.style.cssText = `position:relative;height:${spec.height ?? 400}px;overflow:hidden`; shadowRoot.appendChild(el);
const snow = new Snowflakes({ ...(data.options ?? {}), container: el, width: el.clientWidth || 640, height: spec.height ?? 400 });
for (const s of document.head.querySelectorAll('style')) if (!before.has(s)) shadowRoot.appendChild(s);

